#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <omp.h>

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define DEVICE 0
#define HALO 1 // halo width along one direction when advancing to the next iteration

#define M_SEED 9
int pyramid_height;

int rows, cols;
int* data;
int** wall;
int* result;

void init(int argc, char** argv) {
    if (argc == 4) {
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
        pyramid_height = atoi(argv[3]);
    } else {
        printf("Usage: dynproc row_len col_len pyramid_height\n");
        exit(0);
    }
    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++)
        wall[n] = data + cols * n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; rows > i; i++) {
        for (int j = 0; cols > j; j++) {
            wall[i][j] = rand() % 10;
        }
    }
}

void fatal(char* s) {
    fprintf(stderr, "error: %s\n", s);
}

#define IN_RANGE(x, min, max)   ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) x = (x < (min)) ? min : ((x > (max)) ? max : x)
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

void dynproc_kernel(int iteration, int* wall, int* src, int* results, int cols, int rows, int startStep, int border) {
    int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;
    int blkX = small_block_cols * omp_get_thread_num() - border;
    int blkXmax = blkX + BLOCK_SIZE - 1;
    int xidx = blkX + omp_get_thread_num();
    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

    int W = omp_get_thread_num() - 1;
    int E = omp_get_thread_num() + 1;

    W = (validXmin > W) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool isValid = IN_RANGE(omp_get_thread_num(), validXmin, validXmax);

    int prev[BLOCK_SIZE];
    int result[BLOCK_SIZE];

    if (IN_RANGE(xidx, 0, cols - 1)) {
        prev[omp_get_thread_num()] = src[xidx];
    }

    bool computed;
    for (int i = 0; iteration > i; i++) {
        computed = false;
        if (IN_RANGE(omp_get_thread_num(), i + 1, BLOCK_SIZE - i - 2) &&
            isValid) {
            computed = true;
            int left = prev[W];
            int up = prev[omp_get_thread_num()];
            int right = prev[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);
            int index = cols * (startStep + i) + xidx;
            result[omp_get_thread_num()] = shortest + wall[index];

        }
        if (iteration - 1 == i)
            break;
        if (computed)
            prev[omp_get_thread_num()] = result[omp_get_thread_num()];
    }

    if (computed) {
        results[xidx] = result[omp_get_thread_num()];
    }
}

int calc_path(int* wall, int* results[2], int rows, int cols, int pyramid_height, int blockCols, int borderCols) {
    int src = 1, dst = 0;
    for (int t = 0; rows - 1 > t; t += pyramid_height) {
        int temp = src;
        src = dst;
        dst = temp;
        #pragma omp parallel for
        for (int i = 0; i < blockCols; i++) {
            dynproc_kernel(MIN(pyramid_height, rows - t - 1), wall, results[src], results[dst], cols, rows, t, borderCols);
        }
    }
    return dst;
}

int main(int argc, char** argv) {
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;
    int smallBlockCol = BLOCK_SIZE - (pyramid_height) * HALO * 2;
    int blockCols = cols / smallBlockCol + ((0 == cols % smallBlockCol) ? 0 : 1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",
            pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int* gpuWall;
    int* gpuResult[2];
    int size = rows * cols;

    gpuWall = new int[size - cols];
    gpuResult[0] = new int[cols];
    gpuResult[1] = new int[cols];

    for (int i = 0; i < cols; i++) {
        gpuResult[0][i] = data[i];
    }

    for (int i = 0; i < size - cols; i++) {
        gpuWall[i] = data[cols + i];
    }

    int final_ret = calc_path(gpuWall, gpuResult, rows, cols, pyramid_height, blockCols, borderCols);

    for (int i = 0; i < cols; i++) {
        result[i] = gpuResult[final_ret][i];
    }

    delete[] gpuWall;
    delete[] gpuResult[0];
    delete[] gpuResult[1];

    delete[] data;
    delete[] wall;
    delete[] result;

    return EXIT_SUCCESS;
}
